// Smart scheduler: distributes posts across date range using client intelligence
function smartSchedule(posts, startDate, endDate, intelligence) {
  if(!startDate||!endDate||!posts.length) return posts;
  const start = new Date(startDate);
  const end = new Date(endDate);
  const avoidWeekends = intelligence?.avoid_weekends||false;
  const bestDays = intelligence?.best_posting_days||[];
  const freq = intelligence?.posting_frequency||3;
  const platformTimes = {
    instagram: intelligence?.instagram_best_time||"18:00",
    facebook: intelligence?.facebook_best_time||"12:00",
    tiktok: intelligence?.tiktok_best_time||"19:00",
    linkedin: intelligence?.linkedin_best_time||"09:00",
  };
  // Build list of valid posting days
  const validDays = [];
  const cur = new Date(start);
  const dayNames = ["sunday","monday","tuesday","wednesday","thursday","friday","saturday"];
  while(cur<=end) {
    const dow = cur.getDay();
    if(avoidWeekends && (dow===0||dow===6)) { cur.setDate(cur.getDate()+1); continue; }
    if(bestDays.length && !bestDays.includes(dayNames[dow])) { cur.setDate(cur.getDate()+1); continue; }
    validDays.push(new Date(cur));
    cur.setDate(cur.getDate()+1);
  }
  if(!validDays.length) {
    // Fallback: use all days
    const c2 = new Date(start);
    while(c2<=end) { validDays.push(new Date(c2)); c2.setDate(c2.getDate()+1); }
  }
  // Distribute posts evenly across valid days
  return posts.map((post,i) => {
    const dayIdx = Math.floor(i * validDays.length / posts.length);
    const day = validDays[Math.min(dayIdx, validDays.length-1)];
    const dateStr = day.toISOString().split("T")[0];
    const time = platformTimes[post.platform] || "12:00";
    return {...post, scheduled_date:dateStr, scheduled_time:time};
  });
}

