const POST_TYPE_DURATIONS = {
  image: 60, video: 180, carousel: 120, story: 45, reel: 150,
  social_post: 60, story_reel: 120, caption_copy: 45, graphic_design: 180,
  campaign: 240, ad_creative: 120, blog: 240,
};
const WORKING_START = 9; // 9am
const WORKING_END = 18; // 6pm
const WORKING_MINS = (WORKING_END - WORKING_START) * 60; // 540 mins

// ── Smart Schedule Engine ──────────────────────────────────────
function estimateDuration(post) {
  const base = POST_TYPE_DURATIONS[post.post_type] || POST_TYPE_DURATIONS[post.task_type] || 60;
  const priorityMult = {urgent:1.5, high:1.2, medium:1.0, low:0.8};
  return Math.round(base * (priorityMult[post.priority] || 1.0));
}

function priorityScore(post) {
  const pri = {urgent:4, high:3, medium:2, low:1};
  const score = (pri[post.priority] || 1) * 10;
  const deadline = post.scheduled_date ? Math.max(0, 7 - Math.floor((new Date(post.scheduled_date)-Date.now())/86400000)) : 0;
  return score + deadline;
}

function generateDailySchedule(posts, userEmail, date) {
  const myPosts = posts.filter(p =>
    p.assigned_to === userEmail &&
    !["published","scheduled","rejected"].includes(p.stage)
  ).sort((a,b) => priorityScore(b) - priorityScore(a));

  let cursor = WORKING_START * 60;
  const slots = [];
  for(const post of myPosts) {
    const dur = estimateDuration(post);
    if(cursor + dur > WORKING_END * 60) break;
    slots.push({
      post_id: post.id,
      start_mins: cursor,
      end_mins: cursor + dur,
      start_time: `${String(Math.floor(cursor/60)).padStart(2,'0')}:${String(cursor%60).padStart(2,'0')}`,
      end_time: `${String(Math.floor((cursor+dur)/60)).padStart(2,'0')}:${String((cursor+dur)%60).padStart(2,'0')}`,
      duration_mins: dur,
    });
    cursor += dur + 10;
  }
  return slots;
}

// ── @mention helper ────────────────────────────────────────────
function renderCommentText(text) {
  if(!text) return null;
  const parts = text.split(/(@[\w][\w\s]*?)(?=\s|$|[.,!?])/g);
  return parts.map((part, i) =>
    part.startsWith('@')
      ? <span key={i} style={{color:"var(--accent)",fontWeight:600,background:"var(--accent)11",borderRadius:3,padding:"0 2px"}}>{part}</span>
      : part
  );
}

