// SUPABASE API — direct browser calls, no proxy needed (CORS ✓)
// ════════════════════════════════════════════════════════════════
const SB_HEADERS = {
  "Content-Type": "application/json",
  "apikey": SB_KEY,
  "Authorization": `Bearer ${SB_KEY}`,
};

// Entity name → Supabase table name
const SB_TABLE = {
  Post:"posts", Project:"projects", Client:"clients",
  TeamMember:"team_members", Comment:"comments", Asset:"assets",
  TimeLog:"time_logs", Notification:"notifications", Template:"templates",
  Quote:"quotes", Lead:"leads", LeadActivity:"lead_activities",
  Invoice:"invoices", Payment:"payments",
  Integration:"integrations", IntegrationLog:"integration_logs",
  Subscription:"subscriptions", SubscriptionPayment:"subscription_payments",
  AppSettings:"app_settings", EmailSettings:"email_settings",
  BrandingAssets:"branding_assets", UserProfile:"user_profiles",
  ClientKnowledge:"client_knowledge", ClientDocument:"client_documents",
  PerformanceLog:"performance_logs", AIInsight:"ai_insights",
  TimeEntry:"time_entries", ScheduleOverride:"schedule_overrides",
  ClientContract:"client_contracts",
  ClientIntelligence:"client_intelligence",
  ContentPillar:"content_pillars",
  UserInvitation:"user_invitations",
  AccessRequest:"access_requests",
  ClientUser:"client_users",
  EmailLog:"email_logs",
  ActivityLog:"activity_logs",
  NotificationPrefs:"notification_prefs",
  ClientTask:"client_tasks",
  ClientMemory:"client_memory",
  GeneratedLead:"generated_leads",
  LeadAgentConfig:"lead_agent_configs",
  AgentConfig:"agent_configs",
  AgentLog:"agent_logs",
  AgentRun:"agent_runs",
  SystemSession:"system_sessions",
  MonthlyBrief:"monthly_briefs",
  PushSubscription:"push_subscriptions",
};

function sbTable(entityName) {
  return SB_TABLE[entityName] || entityName.toLowerCase().replace(/([a-z])([A-Z])/g,"$1_$2").toLowerCase() + "s";
}

// Known columns per table — used to strip unknown fields before POST/PATCH
const SB_SCHEMA = {
  projects: ["title","description","client_id","client_name","status","start_date","end_date","platforms","team_members","project_type","posting_start","posting_end"],
  posts: ["project_id","client_id","client_name","title","description","stage","platform","post_type","caption","hashtags","design_urls","design_assets","scheduled_date","scheduled_time","assigned_to","priority","rejection_reason","reel_hook","reel_script","reel_cta","carousel_cover","carousel_slides","music_direction","tov_used","content_language","brief","notes"],
  clients: ["name","email","phone","industry","status","platforms","portal_password","address","website","contact_person","notes"],
  client_tasks: ["client_id","client_name","title","description","task_type","priority","stage","assigned_to","created_by","deliverable_note"],
};
function sbSanitize(tableName, payload) {
  const allowed = SB_SCHEMA[tableName];
  if(!allowed) return payload; // unknown table — pass through
  return Object.fromEntries(Object.entries(payload).filter(([k]) => allowed.includes(k)));
}

// Convert sort string: "-created_date" → "created_at.desc", "payment_date" → "payment_date.asc"
function sbOrder(sort) {
  if(!sort) return null;
  const desc = sort.startsWith("-");
  let col = sort.replace(/^-/, "");
  if(col === "created_date") col = "created_at";
  return `${col}.${desc ? "desc" : "asc"}`;
}

// Query / list — returns {entities:[]}
async function qe(entityName, query={}, sort=null, limit=500) {
  try {
    const tbl = sbTable(entityName);
    const params = new URLSearchParams({ select: "*", limit: String(limit) });
    const order = sbOrder(sort);
    if(order) params.set("order", order);
    // PostgREST filter format: column=eq.value (passed as separate params)
    Object.entries(query).forEach(([k,v]) => params.set(k, `eq.${v}`));
    const r = await fetch(`${SB_URL}/${tbl}?${params}`, { headers: SB_HEADERS });
    if(!r.ok) return {entities:[]};
    const d = await r.json();
    return {entities: Array.isArray(d) ? d : []};
  } catch(e) { return {entities:[]}; }
}

// Create one or more records — returns {entities:[created records with real UUIDs]}
async function ce(entityName, records) {
  try {
    const tbl = sbTable(entityName);
    const results = [];
    for(const rec of records) {
      let payload = {...rec};
      // Strip any local/temp id — Supabase will generate real UUIDs
      const idStr = String(payload.id||"");
      if(!idStr || idStr.startsWith("local_") || idStr.includes("_") || idStr.length < 36) delete payload.id;
      // Strip client-side date field (Supabase uses created_at)
      delete payload.created_date;
      // Strip fields not in the table schema (prevents PGRST204 errors)
      payload = sbSanitize(tbl, payload);
      const r = await fetch(`${SB_URL}/${tbl}`, {
        method: "POST",
        headers: {...SB_HEADERS, "Prefer": "return=representation"},
        body: JSON.stringify(payload),
      });
      if(r.ok) {
        const d = await r.json();
        results.push(Array.isArray(d) ? d[0] : d);
      } else {
        const errBody = await r.text().catch(()=>"");
        console.warn(`[SB] POST ${tbl} ${r.status}:`, errBody);
        results.push({_saveError: true, _status: r.status, _detail: errBody});
      }
    }
    return {entities: results};
  } catch(e) { console.error("[SB] ce error:", e); return {entities:[]}; }
}

// Update a record by ID — PATCH
async function ue(entityName, id, updates) {
  if(!id) return null;
  try {
    const tbl = sbTable(entityName);
    let payload = {...updates};
    delete payload.id; delete payload.created_at; delete payload.created_date;
    payload = sbSanitize(tbl, payload);
    const r = await fetch(`${SB_URL}/${tbl}?id=eq.${id}`, {
      method: "PATCH",
      headers: {...SB_HEADERS, "Prefer": "return=representation"},
      body: JSON.stringify(payload),
    });
    if(!r.ok) return null;
    const d = await r.json();
    return Array.isArray(d) ? d[0] : d;
  } catch(e) { return null; }
}

// Delete a record by ID
async function de(entityName, id) {
  if(!id) return false;
  try {
    const tbl = sbTable(entityName);
    const r = await fetch(`${SB_URL}/${tbl}?id=eq.${id}`, {
      method: "DELETE",
      headers: SB_HEADERS,
    });
    return r.ok;
  } catch(e) { return false; }
}
