// ── Email sender ─────────────────────────────────────────────────
async function sendEmail(to, subject, html, fromName="SocialFlow") {
  const sentAt = new Date().toISOString();
  try {
    const r = await fetch(MAIL_ENDPOINT, {
      method:"POST", headers:{"Content-Type":"application/json"},
      body: JSON.stringify({to, subject, html, from_name:fromName}),
    });
    const d = await r.json();
    const ok = r.ok;
    if(!ok) console.warn("[mail] failed:", d);
    // persist email log
    ce("EmailLog",[{to:Array.isArray(to)?to.join(", "):to, subject, from_name:fromName, status:ok?"sent":"failed", error_message:ok?"":JSON.stringify(d), sent_at:sentAt}]).catch(()=>{});
    return ok;
  } catch(e) {
    console.error("[mail] error:", e);
    ce("EmailLog",[{to:Array.isArray(to)?to.join(", "):to, subject, from_name:fromName, status:"error", error_message:String(e), sent_at:sentAt}]).catch(()=>{});
    return false;
  }
}

// ── Pro AI preferences (model + speed), set from Settings → AI & Tokens ──
function getAIPrefs() {
  let model = "claude-haiku-4-5-20251001", speed = "medium";
  try {
    model = localStorage.getItem("sf_ai_model") || model;
    speed = localStorage.getItem("sf_ai_speed") || speed;
  } catch(e) {}
  return {model, speed};
}
// Speed scales how much Pro is allowed to "think"/write — Low favors fast,
// short replies; High favors slower, more thorough ones. Same model either way.
function speedTokens(speed, base) {
  if(speed==="low") return Math.max(300, Math.round(base*0.5));
  if(speed==="high") return Math.round(base*1.5);
  return base;
}
function trackAIUsage(usage, model) {
  if(!usage) return;
  try {
    const prev = JSON.parse(localStorage.getItem("sf_token_usage")||"{}");
    const updated = {
      input_tokens: (prev.input_tokens||0) + (usage.input_tokens||0),
      output_tokens: (prev.output_tokens||0) + (usage.output_tokens||0),
      total_calls: (prev.total_calls||0) + 1,
      last_call: new Date().toISOString(),
      model,
    };
    localStorage.setItem("sf_token_usage", JSON.stringify(updated));
    window.dispatchEvent(new CustomEvent("sf:tokenusage", {detail: updated}));
  } catch(e) {}
}

// ── Activity logger ───────────────────────────────────────────────
function logActivity(action, category, details="", status="success", errorMsg="", user="system") {
  const entry = {
    action, category, details, status,
    error_message: errorMsg,
    performed_by: user,
    performed_at: new Date().toISOString(),
  };
  ce("ActivityLog",[entry]).then(({entities})=>{
    const saved = entities?.[0];
    // Push the freshly-saved row (with real id) into the live UI immediately,
    // otherwise System Log only reflects what was loaded at page load.
    if(saved && !saved._saveError) window.dispatchEvent(new CustomEvent("sf:activitylog", {detail: saved}));
  }).catch(()=>{});
}

