// ── Reusable email card block ────────────────────────────────────
function emailCard(rows) {
  const trs = rows.map(([label,val,highlight])=>`
    <tr style="border-bottom:1px solid #f3f4f6">
      <td style="padding:11px 16px;font-size:12px;color:#6b7280;font-weight:600;white-space:nowrap">${label}</td>
      <td style="padding:11px 16px;font-size:13px;font-weight:700;color:${highlight||"#111827"};text-align:right">${val}</td>
    </tr>`).join("");
  return `<table width="100%" style="border:1px solid #e5e7eb;border-radius:10px;overflow:hidden;margin:16px 0">${trs}</table>`;
}
function emailDivider(color="#e5e7eb"){return `<hr style="border:none;border-top:1px solid ${color};margin:20px 0"/>`;}
function emailTag(label,color="#6366f1"){return `<span style="display:inline-block;padding:3px 10px;border-radius:99px;font-size:11px;font-weight:700;background:${color}22;color:${color}">${label}</span>`;}

