// ── Default notification preferences ──────────────────────────────
const DEFAULT_NOTIF_PREFS = {
  // Instant emails
  task_assigned: true,
  task_stage_changed: true,
  task_due_soon: true,
  task_overdue: true,
  task_mention: true,
  task_comment: false, // off by default (can be noisy)
  // Project events
  project_created: true,
  project_task_added: false,
  project_deadline_updated: true,
  // Client events
  client_approval_required: true,
  post_approved: true,
  post_rejected: true,
  // Finance events
  invoice_created: true,
  payment_received: true,
  subscription_renewal: true,
  // User events
  user_invited: true,
  access_approved: true,
  access_rejected: true,
  permissions_updated: true,
  // Digest
  daily_digest: true,
  digest_time: "08:00",
  // Mode
  mentions_only: false, // if true, only mention emails are sent
  all_disabled: false, // master kill switch
};

// ── Smart notification dispatcher ─────────────────────────────────
// Checks user prefs before sending. Pass userPrefs = notifPrefs object for that user.
// Pass waNumber to also deliver the notification via WhatsApp.
async function sendNotification(eventType, toEmail, subject, html, userPrefs, waNumber=null) {
  const prefs = {...DEFAULT_NOTIF_PREFS, ...(userPrefs||{})};
  if(prefs.all_disabled) return false;
  if(prefs.mentions_only && eventType !== "task_mention") return false;
  if(prefs[eventType] === false) return false;
  const emailOk = sendEmail(toEmail, subject, html);
  if(waNumber) {
    sendWhatsApp(waNumber, `${subject}\n\nView: ${window.location.origin}`).catch(()=>{});
  }
  return emailOk;
}

async function sendWhatsApp(to, body) {
  if(!FEATURE_FLAGS.whatsapp_notifications) return false;
  try {
    const r = await fetch(WA_ENDPOINT, {
      method:"POST", headers:{"Content-Type":"application/json"},
      body: JSON.stringify({to, body}),
    });
    const d = await r.json();
    if(!r.ok) console.warn("[whatsapp] failed:", d);
    return r.ok;
  } catch(e) { return false; }
}

// ── Web Push: send a push notification to a user's stored subscription(s) ──
async function sendPushNotification(toEmail, title, body, url) {
  try {
    const r = await fetch(PUSH_ENDPOINT, {
      method:"POST", headers:{"Content-Type":"application/json"},
      body: JSON.stringify({ to_email: toEmail, title, body, url: url||window.location.origin }),
    });
    return r.ok;
  } catch(e) { return false; }
}

function urlBase64ToUint8Array(base64String) {
  const padding = "=".repeat((4 - base64String.length % 4) % 4);
  const base64 = (base64String + padding).replace(/-/g, "+").replace(/_/g, "/");
  const rawData = window.atob(base64);
  const outputArray = new Uint8Array(rawData.length);
  for(let i=0; i<rawData.length; i++) outputArray[i] = rawData.charCodeAt(i);
  return outputArray;
}

// ── Web Push: register service worker + subscribe this device, save to backend ──
async function setupPushSubscription(userEmail) {
  if(!userEmail || !("serviceWorker" in navigator) || !("PushManager" in window)) return false;
  try {
    const reg = await navigator.serviceWorker.register("/service-worker.js");
    let permission = Notification.permission;
    if(permission === "default") permission = await Notification.requestPermission();
    if(permission !== "granted") return false;
    let sub = await reg.pushManager.getSubscription();
    if(!sub) {
      sub = await reg.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: urlBase64ToUint8Array(VAPID_PUBLIC_KEY),
      });
    }
    const key = sub.toJSON();
    // Avoid duplicate rows — only save if this exact endpoint isn't already stored
    const already = await qe("PushSubscription", {endpoint: key.endpoint});
    if(!already.entities?.length) {
      await ce("PushSubscription", [{
        user_email: userEmail,
        endpoint: key.endpoint,
        p256dh: key.keys?.p256dh||"",
        auth: key.keys?.auth||"",
      }]);
    }
    return true;
  } catch(e) { console.warn("[push] setup failed:", e); return false; }
}

async function publishPost(post, integration) {
  const creds = parseJ(integration.credentials||"{}");
  const r = await fetch(PUBLISH_ENDPOINT, {
    method:"POST", headers:{"Content-Type":"application/json"},
    body: JSON.stringify({
      platform: integration.app_key,
      page_id: creds.page_id||"",
      access_token: creds.access_token||"",
      message: [post.caption, post.hashtags].filter(Boolean).join("\n\n"),
      image_url: (parseJ(post.design_urls||"[]"))[0]||"",
    }),
  });
  const d = await r.json();
  if(!r.ok) throw new Error(d.error||"Publish failed");
  return d;
}

const ai = async (prompt, maxTokens=1000) => {
  const r = await fetch(AI_ENDPOINT, {
    method:"POST",
    headers: AI_HEADERS,
    body: JSON.stringify({ model:"claude-sonnet-4-6", max_tokens:maxTokens, messages:[{role:"user",content:prompt}] })
  });
  if(!r.ok) {
    const errText = await r.text();
    console.error("AI API error:", r.status, errText);
    throw new Error(`AI API error ${r.status}: ${errText.slice(0,120)}`);
  }
  const d = await r.json();
  return d.content?.map(b=>b.text||"").join("") || "";
};

