// ── Format client memory for AI injection ──
const formatClientMemory = (clientId, clientMemory=[]) => {
  const mem = clientMemory.filter(m=>m.client_id===clientId);
  if(!mem.length) return "";
  // Priority: manual > ai > auto
  const priority = {manual:0, ai:1, auto:2};
  const sorted = [...mem].sort((a,b)=>priority[a.type]-priority[b.type]);
  const manual = sorted.filter(m=>m.type==="manual");
  const ai = sorted.filter(m=>m.type==="ai");
  const auto = sorted.filter(m=>m.type==="auto");
  const fmt = (arr) => arr.map(m=>` • ${m.key.replace(/_/g," ")}: ${m.value}`).join("\n");
  return [
    manual.length ? `[BRAND GUIDELINES]\n${fmt(manual)}` : "",
    ai.length ? `[AI LEARNED]\n${fmt(ai)}` : "",
    auto.length ? `[BEHAVIORAL PATTERNS]\n${fmt(auto)}` : "",
  ].filter(Boolean).join("\n");
};

// Strip [ACTION:{...}] blocks from display text using balanced-brace scan
// (regex with lazy {...} fails when JSON contains nested } or escaped quotes)
const stripActionBlocks = (text) => {
  if(!text) return "";
  const marker = "[ACTION:";
  let out = "", i = 0;
  while(i < text.length){
    const next = text.indexOf(marker, i);
    if(next === -1){ out += text.slice(i); break; }
    out += text.slice(i, next);
    const start = next + marker.length;
    if(text[start] !== "{"){ out += text.slice(next, start); i = start; continue; }
    let depth = 0, j = start, inStr = false, esc = false, found = false;
    for(; j < text.length; j++){
      const ch = text[j];
      if(esc){ esc = false; continue; }
      if(ch === "\\"){ esc = true; continue; }
      if(inStr){ if(ch === "\"") inStr = false; continue; }
      if(ch === "\""){ inStr = true; continue; }
      if(ch === "{") depth++;
      else if(ch === "}"){ depth--; if(depth === 0){ j++; found = true; break; } }
    }
    if(found && text[j] === "]"){ i = j + 1; }
    else { out += text.slice(next, start); i = start; }
  }
  return out.trim();
};

