  const addProject = async (formData, pillars, intelligence) => {
    if(!formData.client_id) { setToast(" Pick a client before creating a project — every project must belong to one."); return false; }
    // 1. Create project
    const projPayload = {
      title: formData.name,
      client_id: formData.client_id,
      client_name: formData.client_name,
      description: formData.description,
      project_type: formData.project_type,
      status: "active",
      platforms: formData.platforms||[],
      start_date: formData.start_date,
      end_date: formData.deadline, // DB column is end_date
      posting_start:formData.posting_start||null,
      posting_end: formData.posting_end||null,
    };
    const localProj = {...projPayload, id:uid(), created_at:new Date().toISOString()};
    setData(d=>({...d, projects:[localProj,...d.projects]}));
    let projectId = localProj.id;
    try {
      const res = await ce("Project",[projPayload]);
      const real = res.entities?.[0];
      if(real?._saveError) { setToast(` Project save failed (${real._status}). Changes may not persist after refresh.`); }
      else if(real?.id) {
        projectId = real.id;
        setData(d=>({...d,projects:d.projects.map(p=>p.id===localProj.id?{...p,...real}:p)}));
      }
    } catch(e){ setToast(` Network error saving project: ${e.message}`); }

    // 2. Generate posts from content pillars
    const allPosts = [];
    (pillars||[]).forEach(pillar=>{
      if(!pillar.pillar_name) return;
      const count = parseInt(pillar.post_count)||1;
      for(let i=1;i<=count;i++) {
        allPosts.push({
          project_id: projectId,
          client_id: formData.client_id,
          client_name: formData.client_name,
          title: `${pillar.pillar_name} — Post ${i}`,
          description: pillar.description||"",
          stage: "content_creation",
          platform: (formData.platforms||[])[0]||pillar.platform||"instagram",
          post_type: pillar.post_type||"static",
          assigned_to: pillar.assigned_to||"",
          priority: "medium",
        });
      }
    });

    // 3. Smart schedule if posting dates set
    const scheduledPosts = formData.posting_start&&formData.posting_end
      ? smartSchedule(allPosts, formData.posting_start, formData.posting_end, intelligence)
      : allPosts;

    // 4. Save all posts
    if(scheduledPosts.length>0) {
      const localPosts = scheduledPosts.map(p=>({...p, id:uid(), created_at:new Date().toISOString()}));
      setData(d=>({...d,posts:[...localPosts,...d.posts]}));
      ce("Post",scheduledPosts.map(p=>{const copy={...p};delete copy.id;delete copy.created_at;return copy;}))
        .then(res=>{
          const reals=res.entities||[];
          setData(d=>{
            let posts=[...d.posts];
            localPosts.forEach((lp,i)=>{ if(reals[i]?.id) posts=posts.map(p=>p.id===lp.id?{...p,...reals[i]}:p); });
            return {...d,posts};
          });
        }).catch(()=>{});
      // Save content pillars
      ce("ContentPillar",(pillars||[]).filter(p=>p.pillar_name).map(p=>({...p,project_id:projectId,id:undefined}))).catch(()=>{});
    }

    // Notify assigned team members
    const teamEmails = (formData.team_members||[]).filter(e=>e!==currentUser?.email);
    teamEmails.forEach(email=>{
      const m = data.team.find(t=>t.email===email);
      if(m) {
        const prefs = getNotifPrefs(email);
        sendNotification("project_created", email,
          `[SocialFlow] New project: ${formData.name}`,
          EMAIL_TEMPLATES.projectCreated(m.name, formData.name, formData.client_name, formData.end_date?fmtDate(formData.end_date):"TBD", currentUser?.name),
          prefs
        ).catch(()=>{});
      }
    });
    logActivity("Project Created","clients",`New project: ${formData.name} for ${formData.client_name} (${scheduledPosts.length} posts)`,"success","",currentUser?.email||"admin");
    setToast(` "${formData.name}" created with ${scheduledPosts.length} posts${formData.posting_start?" — smart scheduled":""}!`);
    return true;
  };

