  // ── Client Memory handlers ──────────────────────────────────────
  const upsertClientMemory = async (clientId, clientName, key, value, type="manual", opts={}) => {
    if(!clientId||!key||!value) return;
    const now = new Date().toISOString();
    const extra = {
      source: opts.source||"",
      confidence: typeof opts.confidence==="number" ? opts.confidence : null,
      is_private: !!opts.is_private,
      created_by: opts.created_by||"",
    };
    const existing = (data.clientMemory||[]).find(m=>m.client_id===clientId&&m.key===key);
    if(existing && opts.keepBoth) {
      // duplicate-key keep-both: append a numeric suffix
      let n=2; while((data.clientMemory||[]).find(m=>m.client_id===clientId&&m.key===`${key}_${n}`)) n++;
      key = `${key}_${n}`;
    }
    if(existing && !opts.keepBoth) {
      const updated = {...existing, value, type, updated_at:now, ...extra};
      setData(d=>({...d, clientMemory:d.clientMemory.map(m=>m.client_id===clientId&&m.key===existing.key?updated:m)}));
      ue("ClientMemory", existing.id, {value, type, updated_at:now, ...extra}).catch(()=>{});
    } else {
      const local = {id:uid(), client_id:clientId, client_name:clientName, key, value, type, created_at:now, updated_at:now, ...extra};
      setData(d=>({...d, clientMemory:[local,...(d.clientMemory||[])]}));
      ce("ClientMemory",[{client_id:clientId, client_name:clientName, key, value, type, updated_at:now, ...extra}])
        .then(res=>{ const real=res.entities?.[0]; if(real?.id) setData(d=>({...d,clientMemory:d.clientMemory.map(m=>m.id===local.id?{...m,...real}:m)})); })
        .catch(()=>{});
    }
  };

