  const confirmPayment = async (invoice, payData) => {
    const localPay = {...payData,id:uid(),created_date:new Date().toISOString()};
    setData(d=>({...d,payments:[...d.payments,localPay]}));
    ce("Payment",[payData]).catch(()=>{});
    const allPays = [...data.payments,localPay].filter(p=>p.invoice_id===invoice.id);
    const totalPaid = allPays.reduce((a,p)=>a+(p.amount||0),0);
    const balance = Math.max(0,invoice.total-totalPaid);
    const newStatus = balance<=0?"paid":totalPaid>0?"partially_paid":"unpaid";
    const updatedInv = {...invoice,amount_paid:totalPaid,balance_due:balance,status:newStatus};
    setData(d=>({...d,invoices:d.invoices.map(i=>i.id===invoice.id?updatedInv:i)}));
    ue("Invoice", invoice.id, {amount_paid:totalPaid,balance_due:balance,status:newStatus}).catch(()=>{});
    logActivity("Payment Recorded","finance",`${fmtMoney(payData.amount,invoice.currency||"USD")} for Invoice ${invoice.invoice_number} (${invoice.client_name}) — status: ${newStatus}`,"success","",currentUser?.email||"admin");
    // Notify admins/accountants of payment
    data.team.filter(m=>["admin","accountant"].includes(m.role)&&m.email!==currentUser?.email).forEach(m=>{
      const prefs = getNotifPrefs(m.email);
      sendNotification("payment_received", m.email,
        `[SocialFlow] Payment recorded — ${invoice.invoice_number}`,
        EMAIL_TEMPLATES.paymentReceived(m.name, invoice.invoice_number, fmtMoney(payData.amount,invoice.currency||"USD"), invoice.currency||"USD", invoice.client_name),
        prefs
      ).catch(()=>{});
    });
    if(newStatus==="paid") setToast(` Invoice ${invoice.invoice_number} fully paid!`);
    else setToast(`Payment of ${fmtMoney(payData.amount,invoice.currency||"USD")} recorded`);
  };

